import xml.etree.ElementTree as ET

def validate_xml(file):
    tree = ET.parse(file)
    root = tree.getroot()

    # Validate the XML document structure
    if not root.tag == 'document':
        raise ValueError('Invalid root tag')

    # Validate the XML document contents
    for child in root:
        if child.tag not in ['title', 'author', 'publisher']:
            raise ValueError('Invalid child tag')

    return True